// START of Epic A (Core Mobile Inspection Workflow), Story A.3:implementation: Offline-First Architecture | As a technician working in a remote location, I want to complete my entire inspection without a network connection, so that my work is not interrupted and data is safely persisted until I can sync.
import '../models/saved_form_state.dart';
// END of Epic A, Story A.3:implementation

/// Form State Service
/// Manages form data, real-time validation, auto-save, and completion tracking
/// Implements FormState interface from DynamicWidgetFactory
class FormStateService extends ChangeNotifier implements widget_factory.FormState {
  @override
  final String inspectionId;
  final TemplateSchema template;
  final ValidationService _validationService;
  final InspectionDatabase _database;

  // Form data storage
  Map<String, dynamic> _formData = {};
  Map<String, ValidationError> _validationErrors = {};
  double _completionPercentage = 0.0;
  DateTime? _lastSavedAt;

  // Auto-save debounce timer (30 seconds)
  Timer? _autoSaveTimer;
  static const _autoSaveDuration = Duration(seconds: 30);

  // State flags
  bool _isLoading = false;
  bool _isSaving = false;

  FormStateService({
    required this.inspectionId,
    required this.template,
    ValidationService? validationService,
    InspectionDatabase? database,
  })  : _validationService = validationService ?? ValidationService.instance,
        _database = database ?? InspectionDatabase.instance;

  // Getters
  Map<String, dynamic> get formData => Map.unmodifiable(_formData);
  Map<String, ValidationError> get validationErrors => Map.unmodifiable(_validationErrors);
  double get completionPercentage => _completionPercentage;
  DateTime? get lastSavedAt => _lastSavedAt;
  bool get isLoading => _isLoading;
  bool get isSaving => _isSaving;
  bool get hasUnsavedChanges => _autoSaveTimer?.isActive ?? false;

  /// Initialize form state - load from database or create new
  Future<void> initialize() async {
    _isLoading = true;
    notifyListeners();

    try {
      final savedState = await loadFormState();
      if (savedState != null) {
        _formData = Map.from(savedState.formData);
        _completionPercentage = savedState.completionPercentage;
        _lastSavedAt = savedState.lastSavedAt;
        debugPrint('✅ Form state loaded from database (last saved: $_lastSavedAt)');
      } else {
        _formData = {};
        _completionPercentage = 0.0;
        debugPrint('✨ New form state initialized');
      }

      // Initial validation
      _validationErrors = _validationService.validateForm(template, _formData);
      _calculateCompletionPercentage();
    } catch (e) {
      debugPrint('❌ Error initializing form state: $e');
      rethrow;
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  /// Get field value (implements FormState interface)
  @override
  dynamic getValue(String fieldId) => _formData[fieldId];

  /// Set field value with real-time validation and debounced auto-save
  /// Implements AC-A.2.5 (real-time validation) and AC-A.2.6 (auto-save)
  @override
  void setValue(String fieldId, dynamic value) {
    // Update form data
    _formData[fieldId] = value;

    // Real-time validation (AC-A.2.5)
    final field = _findField(fieldId);
    if (field != null) {
      final error = _validationService.validateField(fieldId, value, field.validation);
      if (error != null) {
        _validationErrors[fieldId] = error;
      } else {
        _validationErrors.remove(fieldId);
      }
    }

    // Recalculate completion percentage (AC-A.2.11)
    _calculateCompletionPercentage();

    // Restart debounced auto-save timer (AC-A.2.6)
    _restartAutoSaveTimer();

    notifyListeners();
  }

  /// Get validation error for field
  ValidationError? getError(String fieldId) => _validationErrors[fieldId];

  /// Check if field has error
  bool hasError(String fieldId) => _validationErrors.containsKey(fieldId);

  /// Check if form is valid
  bool get isValid => _validationErrors.isEmpty;

  /// Calculate completion percentage
  /// Implements AC-A.2.11: (required_filled / required_total * 100)
  void _calculateCompletionPercentage() {
    final requiredFields = _getRequiredFields();
    if (requiredFields.isEmpty) {
      _completionPercentage = 100.0;
      return;
    }

    int filledCount = 0;
    for (final field in requiredFields) {
      final value = _formData[field.id];
      if (value != null && value.toString().trim().isNotEmpty) {
        filledCount++;
      }
    }

    _completionPercentage = (filledCount / requiredFields.length) * 100.0;
  }

  /// Get all required fields from template
  List<FieldSchema> _getRequiredFields() {
    final requiredFields = <FieldSchema>[];
    for (final section in template.sections) {
      for (final field in section.fields) {
        if (field.validation?.required == true) {
          requiredFields.add(field);
        }
      }
    }
    return requiredFields;
  }

  /// Find field by ID
  FieldSchema? _findField(String fieldId) {
    for (final section in template.sections) {
      for (final field in section.fields) {
        if (field.id == fieldId) {
          return field;
        }
      }
    }
    return null;
  }

  /// Restart auto-save debounce timer
  void _restartAutoSaveTimer() {
    _autoSaveTimer?.cancel();
    _autoSaveTimer = Timer(_autoSaveDuration, _autoSave);
  }

  /// Auto-save to database (debounced)
  /// Implements AC-A.2.6: Auto-save every 30 seconds (debounced)
  Future<void> _autoSave() async {
    if (_isSaving) return;

    _isSaving = true;
    notifyListeners();

    try {
      await saveFormState();
      _lastSavedAt = DateTime.now();
      debugPrint('💾 Form auto-saved at $_lastSavedAt');
    } catch (e) {
      debugPrint('❌ Auto-save failed: $e');
    } finally {
      _isSaving = false;
      notifyListeners();
    }
  }

  /// Manual save (useful for explicit save actions)
  Future<void> save() async {
    _autoSaveTimer?.cancel(); // Cancel pending auto-save
    await _autoSave();
