  /// Sync templates from Supabase to SQLite
  /// Implements offline-first architecture: Supabase → SQLite → UI
  /// This method downloads all published template versions from Supabase
  /// and stores them in local SQLite for offline access
  /// Should be called on app startup and periodically in background
  ///
  /// Story 3.1A: Basic full sync implementation
  /// TODO Epic 7: Enhance with advanced sync features (Story 7.2 - Delta Sync)
  ///   - Implement cursor-based incremental sync (only fetch templates updated since last sync)
  ///   - Add compression for sync payloads (reduce bandwidth by 70%)
  ///   - Add selective sync based on user assignments
  ///   - Add network condition awareness (WiFi vs cellular)
  ///   - Add background sync with WorkManager/Background Fetch
  ///   - Add sync progress tracking with detailed status
  Future<void> syncTemplatesFromSupabase() async {
    if (_database == null) {
      throw Exception('Database not initialized. Call initialize() first.');
    }

    try {
      debugPrint('Starting template sync from Supabase...');

      // Query all published template versions from Supabase
      // Using Supabase ONLY for sync, not for direct UI queries
      final response = await Supabase.instance.client
          .from('template_versions')
          .select(
            'id, template_id, version, schema_json, published_at, created_at, updated_at',
          )
          .not('published_at', 'is', null)
          .order('version', ascending: false);

      final List<dynamic> templates = response as List<dynamic>;
      debugPrint(
        'Fetched ${templates.length} published templates from Supabase',
      );

      // Insert/update each template in local SQLite
      for (final template in templates) {
        // Convert schema_json to string if it's a Map
        final schemaJson = template['schema_json'];
        final schemaJsonStr = schemaJson is String
            ? schemaJson
            : jsonEncode(schemaJson);

        await _database!.insert('template_versions', {
          'id': template['id'],
          'template_id': template['template_id'],
          'version': template['version'],
          'schema_json': schemaJsonStr,
          'published_at': template['published_at'],
          'created_at': template['created_at'],
          'updated_at': template['updated_at'],
          'synced_at': DateTime.now().toIso8601String(),
        }, conflictAlgorithm: ConflictAlgorithm.replace);
      }

      debugPrint('Successfully synced ${templates.length} templates to SQLite');
    } catch (e) {
      debugPrint('Template sync failed: ${e.toString()}');
      rethrow;
    }
  }

  /// Check if newer template versions are available on Supabase
  /// Compares local SQLite synced_at timestamps with Supabase updated_at
  /// Returns true if sync is needed
  Future<bool> needsTemplateSync() async {
    if (_database == null) return false;

    try {
      // Get most recent synced_at from local SQLite
      final result = await _database!.query(
        'template_versions',
        columns: ['synced_at'],
        orderBy: 'synced_at DESC',
        limit: 1,
      );

      if (result.isEmpty) {
        // No local templates, sync needed
        return true;
      }

      final lastSyncedAt = DateTime.parse(result.first['synced_at'] as String);

      // Check if any templates were updated on Supabase after last sync
      final response = await Supabase.instance.client
          .from('template_versions')
          .select('id')
          .not('published_at', 'is', null)
          .gt('updated_at', lastSyncedAt.toIso8601String())
          .limit(1);

      // If any results, sync is needed
      return (response as List).isNotEmpty;
    } catch (e) {
      debugPrint('Error checking template sync status: ${e.toString()}');
