  AuthService._internal();

  /// Lazy-loaded Supabase client to avoid initialization timing issues
  SupabaseClient get _supabase {
    if (!Supabase.instance.isInitialized) {
      throw Exception('Supabase is not initialized. Ensure Supabase.initialize() is called before using AuthService.');
    }
    return Supabase.instance.client;
  }

  /// Initialize auth service after Supabase is ready
  void initialize() {
    if (Supabase.instance.isInitialized) {
      _initializeAuthStateListener();
    }
  }
  StreamSubscription<AuthState>? _authStateSubscription;

  User? _currentUser;
  Session? _currentSession;
  bool _isLoading = false;
  String? _errorMessage;

  /// Current authenticated user
  User? get currentUser => _currentUser;

  /// Current session
  Session? get currentSession => _currentSession;

  /// Loading state for auth operations
  bool get isLoading => _isLoading;

  /// Current error message
  String? get errorMessage => _errorMessage;

  /// Whether user is authenticated
  bool get isAuthenticated => _currentUser != null && _currentSession != null;

  /// Initialize auth state listener
  void _initializeAuthStateListener() {
    _authStateSubscription = _supabase.auth.onAuthStateChange.listen(
      (AuthState data) {
        _currentUser = data.session?.user;
        _currentSession = data.session;
        _clearError();
        notifyListeners();
      },
      onError: (error) {
        _setError('Auth state error: ${error.toString()}');
      },
    );

    // Set initial auth state
    _currentUser = _supabase.auth.currentUser;
    _currentSession = _supabase.auth.currentSession;
  }

