    switch (value.toLowerCase()) {
      case 'overview':
        return PhotoType.overview;
      case 'closeup':
      case 'close-up':
        return PhotoType.closeup;
      case 'additional':
        return PhotoType.additional;
      default:
        throw ArgumentError('Invalid photo type: $value. Must be overview, closeup, or additional.');
    }
  }
}

