{"output":"import 'package:flutter/foundation.dart';
import 'package:postgrest/postgrest.dart';
import 'package:supabase_flutter/supabase_flutter.dart';

import '../models/equipment.dart' as equipment_model;
import 'local_storage_service.dart';

typedef EquipmentFetcher = Future<List<Map<String, dynamic>>> Function(
  String technicianId,
);

class EquipmentRegisterService {
  EquipmentRegisterService._internal({
    required SupabaseClient supabaseClient,
    required LocalStorageService localStorage,
    required EquipmentFetcher fetcher,
    required DateTime Function() clock,
    required Session? Function() sessionProvider,
  })  : _supabaseClient = supabaseClient,
        _localStorage = localStorage,
        _fetchRemote = fetcher,
        _clock = clock,
        _sessionProvider = sessionProvider;

  static EquipmentRegisterService? _singleton;

  factory EquipmentRegisterService({
    SupabaseClient? supabaseClient,
    LocalStorageService? localStorage,
    EquipmentFetcher? remoteFetcher,
    DateTime Function()? clock,
    Session? Function()? sessionProvider,
  }) {
    final resolvedClient = supabaseClient ?? Supabase.instance.client;
    final resolvedStorage = localStorage ?? LocalStorageService();
    final resolvedClock = clock ?? () => DateTime.now();
    final resolvedFetcher = remoteFetcher ??
        _defaultFetcher(
          resolvedClient,
        );
    final resolvedSessionProvider = sessionProvider ??
        () => resolvedClient.auth.currentSession;

    final useSingleton = supabaseClient == null &&
        localStorage == null &&
        remoteFetcher == null &&
        clock == null &&
        sessionProvider == null;

    if (useSingleton) {
      _singleton ??= EquipmentRegisterService._internal(
        supabaseClient: resolvedClient,
        localStorage: resolvedStorage,
        fetcher: resolvedFetcher,
        clock: resolvedClock,
        sessionProvider: resolvedSessionProvider,
      );
      return _singleton!;
    }

    return EquipmentRegisterService._internal(
      supabaseClient: resolvedClient,
      localStorage: resolvedStorage,
      fetcher: resolvedFetcher,
      clock: resolvedClock,
      sessionProvider: resolvedSessionProvider,
    );
  }

  final SupabaseClient _supabaseClient;
  final LocalStorageService _localStorage;
  final EquipmentFetcher _fetchRemote;
  final DateTime Function() _clock;
  final Session? Function() _sessionProvider;

  static EquipmentFetcher _defaultFetcher(SupabaseClient client) {
    return (String technicianId) async {
      final response = await client
          .from('equipment_register')
          .select(
            '''
id,
asset_number,
asset_name,
asset_type,
manufacturer,
model_number,
serial_number,
installation_date,
last_calibration_date,
next_calibration_due,
metadata,
barcode_data,
gps_coordinates,
is_active,
technician_id,
customer_id
''',
          )
          .eq('technician_id', technicianId)
          .eq('is_active', true);

      return (response as List<dynamic>).cast<Map<String, dynamic>>();
    };
  }

  Future<List<equipment_model.Equipment>> getAssignedEquipment(
    String technicianId,
  ) async {
    final trimmedTechnicianId = technicianId.trim();
    if (trimmedTechnicianId.isEmpty) {
      throw ArgumentError('technicianId cannot be empty');
    }

    final session = _currentSession;
    final customerId = _resolveCustomerId(session);

    try {
      final remoteRows = await _fetchRemote(trimmedTechnicianId);
      final timestamp = _clock();
      final equipment = remoteRows
          .map(
            (row) => equipment_model.Equipment.fromSupabase(
              row,
              technicianId: trimmedTechnicianId,
              customerId: customerId,
              cachedAt: timestamp,
            ),
          )
          .toList(growable: false);

      try {
        await _localStorage.cacheEquipment(
          technicianId: trimmedTechnicianId,
          customerId: customerId,
          equipment: equipment,
        );
      } catch (cacheError) {
        debugPrint('⚠️ Equipment cache update failed: $cacheError');
      }

      return equipment;
    } catch (error) {
      debugPrint('⚠️ Equipment register query failed: $error');
      if (error is PostgrestException) {
        debugPrint(
          '⚠️ Supabase error code: ${error.code} (details: ${error.details})',
        );
      }

      final cached = await _localStorage.getCachedEquipment(
        trimmedTechnicianId,
      );
      if (cached.isNotEmpty) {
        return cached;
      }
      return const <equipment_model.Equipment>[];
    }
  }

  Future<List<equipment_model.Equipment>> getCachedEquipment(
    String technicianId,
  ) {
    return _localStorage.getCachedEquipment(technicianId);
  }

  Future<void> clearCache(String technicianId) {
    return _localStorage.clearEquipmentCache(technicianId);
  }

  Session? get _currentSession => _sessionProvider();

  String? _resolveCustomerId(Session? session) {
    try {
      return session?.user.appMetadata['customer_id'] as String?;
    } catch (_) {
      return null;
    }
  }
}
