import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:sqflite/sqflite.dart';
import 'package:uuid/uuid.dart';
import 'package:supabase_flutter/supabase_flutter.dart';
import '../services/schema_parser.dart';
import '../services/gps_service.dart';
import '../models/photo_metadata.dart';
import '../widgets/dynamic_widget_factory.dart';

/// ============================================================================
/// OFFLINE-FIRST ARCHITECTURE - INSPECTION PROVIDER
/// ============================================================================
///
/// Story 3.1A: Basic offline-first implementation with SQLite + Outbox pattern
/// Epic 7 Roadmap: Advanced sync features planned for Weeks 13-14 (see TODOs below)
///
/// This provider implements a strict offline-first architecture where:
///
/// 1. **SQLite is the SINGLE SOURCE OF TRUTH for UI**
///    - All UI components query ONLY SQLite (never Supabase directly)
///    - Exception: Authentication queries Supabase directly
///
/// 2. **Supabase is ONLY used for sync operations**
///    - syncTemplatesFromSupabase(): Downloads templates Supabase → SQLite
///    - Outbox pattern: Queues local changes for upload to Supabase
///    - Background sync service uploads outbox changes SQLite → Supabase
///
/// 3. **Data Flow**
///    ```
///    DOWNLOAD (Read):  Supabase → SQLite → UI
///    UPLOAD (Write):   UI → SQLite → Outbox → Supabase
///    ```
///
/// 4. **Tables in SQLite**
///    - inspections: Local inspection metadata
///    - inspection_values: Field-level form data (key-value store)
///    - template_versions: Template schemas (synced from Supabase)
///    - outbox: Pending changes to sync to Supabase
///
/// 5. **Sync Strategy**
///    - On app startup: Check needsTemplateSync() and sync if needed
///    - Periodic background: Sync templates every X hours
///    - Real-time: Outbox uploads happen immediately when online
///    - Conflict resolution: Last-write-wins (timestamp-based)
///
/// 6. **Benefits of Offline-First**
///    - App works 100% offline (critical for field technicians)
///    - Fast UI (no network latency)
///    - Predictable performance (SQLite is always fast)
///    - Data safety (auto-saved to SQLite, synced when online)
///
/// ============================================================================

/// Inspection Model
class Inspection {
  final String id;
  final String templateId;
  final String templateVersionId;
  final String status; // draft, in_progress, completed, submitted
  final DateTime createdAt;
  final DateTime updatedAt;
  final GpsCoordinates? gpsLocation; // GPS coordinates captured on inspection start

  Inspection({
    required this.id,
    required this.templateId,
    required this.templateVersionId,
    this.status = 'draft',
    DateTime? createdAt,
    DateTime? updatedAt,
    this.gpsLocation,
  }) : createdAt = createdAt ?? DateTime.now(),
       updatedAt = updatedAt ?? DateTime.now();

  Map<String, dynamic> toJson() => {
    'id': id,
    'template_id': templateId,
    'template_version_id': templateVersionId,
    'status': status,
    'created_at': createdAt.toIso8601String(),
    'updated_at': updatedAt.toIso8601String(),
    if (gpsLocation != null) 'gps_location': gpsLocation!.toJson(),
  };

  factory Inspection.fromJson(Map<String, dynamic> json) => Inspection(
    id: json['id'],
    templateId: json['template_id'],
    templateVersionId: json['template_version_id'],
    status: json['status'] ?? 'draft',
    createdAt: DateTime.parse(json['created_at']),
    updatedAt: DateTime.parse(json['updated_at']),
    gpsLocation: json['gps_location'] != null
        ? GpsCoordinates.fromJson(json['gps_location'])
        : null,
  );
}

/// Inspection Provider
/// Implements AC 3.1A.4 - Form State Management with Provider Pattern
class InspectionProvider extends ChangeNotifier implements FormState {
  static InspectionProvider? _instance;
  static InspectionProvider get instance {
    _instance ??= InspectionProvider._internal();
    return _instance!;
  }

  InspectionProvider._internal();

  // Dependencies
  Database? _database;
  final Uuid _uuid = const Uuid();
  Timer? _autoSaveTimer;

  // State
  Inspection? _currentInspection;
  TemplateSchema? _currentTemplate;
  final Map<String, dynamic> _formData = {};
  final Map<String, FieldUiState> _fieldUiStates = {};
  bool _isLoading = false;
  String? _errorMessage;

  // Getters
  Inspection? get currentInspection => _currentInspection;
  TemplateSchema? get currentTemplate => _currentTemplate;
  Map<String, dynamic> get formData => Map.unmodifiable(_formData);
  bool get isLoading => _isLoading;
  String? get errorMessage => _errorMessage;
  Database? get database => _database;

  // FormState interface implementation
  @override
  String? get inspectionId => _currentInspection?.id;

  /// Initialize database connection
  Future<void> initialize(Database database) async {
    _database = database;
    await _ensureTablesExist();
  }

  /// Ensure required SQLite tables exist (AC 3.1A.4 constraint)
  /// Follows coding standards section 7: Database Standards
  Future<void> _ensureTablesExist() async {
    if (_database == null) return;

    // Inspections table with standard fields (coding-standards.md section 7)
    await _database!.execute('''
      CREATE TABLE IF NOT EXISTS inspections (
        id TEXT PRIMARY KEY,
        template_id TEXT NOT NULL,
        template_version_id TEXT NOT NULL,
        status TEXT DEFAULT 'draft',
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now')),
        created_by TEXT,
        customer_id TEXT NOT NULL DEFAULT 'default-customer'
      )
    ''');

    // Inspection values table
    await _database!.execute('''
      CREATE TABLE IF NOT EXISTS inspection_values (
        id TEXT PRIMARY KEY,
        inspection_id TEXT NOT NULL,
        field_id TEXT NOT NULL,
        value_json TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
        updated_at TEXT NOT NULL DEFAULT (datetime('now')),
        FOREIGN KEY (inspection_id) REFERENCES inspections(id) ON DELETE CASCADE
      )
    ''');

    // Template versions table (synced from Supabase)
    await _database!.execute('''
      CREATE TABLE IF NOT EXISTS template_versions (
        id TEXT PRIMARY KEY,
        template_id TEXT NOT NULL,
        version INTEGER NOT NULL,
        schema_json TEXT NOT NULL,
        published_at TEXT,
        created_at TEXT NOT NULL DEFAULT (datetime('now')),
