/// Form State interface for field values
abstract class FormState {
  dynamic getValue(String fieldId);
  void setValue(String fieldId, dynamic value);
  String? get inspectionId; // Add inspection ID for photo persistence
}

/// Widget Builder Function type
typedef WidgetBuilder = Widget Function(
  FieldSchema schema,
  FormState formState,
  FieldUiState uiState,
);

/// Dynamic Widget Factory
/// Maps field types to Flutter widgets
/// Implements AC 3.1A.2
class DynamicWidgetFactory {
  static DynamicWidgetFactory? _instance;
  static DynamicWidgetFactory get instance {
    _instance ??= DynamicWidgetFactory._internal();
    return _instance!;
  }

  DynamicWidgetFactory._internal() {
    _registerBuilders();
  }

  final Map<String, WidgetBuilder> _builders = {};

  /// Register all field type builders
  void _registerBuilders() {
    // Text fields
    _builders['text_field'] = _buildTextField;
    _builders['textarea_field'] = _buildTextAreaField;
    _builders['number_field'] = _buildNumberField;

    // Selection fields
    _builders['dropdown_field'] = _buildDropdownField;
    _builders['multi_select_field'] = _buildMultiSelectField; // Story A.2: AC-A.2.2
    _builders['checkbox_field'] = _buildCheckboxField;
    _builders['radio_field'] = _buildRadioField; // Story A.2: AC-A.2.2

    // Date/time fields
    _builders['date_field'] = _buildDateField;
    _builders['time_field'] = _buildTimeField; // Story A.2: AC-A.2.2

    // Media fields
    _builders['photo_field'] = _buildPhotoField;
    _builders['signature_field'] = _buildSignatureField;

    // Rating fields
    _builders['rating_field'] = _buildRatingField; // Story A.2: AC-A.2.2

    // Hardware fields
    _builders['gps_field'] = _buildGpsField;
    _builders['barcode_field'] = _buildBarcodeField;

    // Specialized fields
    _builders['equipment_diagram_field'] = _buildEquipmentDiagramField;
    _builders['tarp_cascade_field'] = _buildTarpCascadeField;
    _builders['certification_badge_field'] = _buildCertificationBadgeField;
  }

  /// Create a widget for a field
  /// Returns the appropriate widget or fallback if type unknown
  Widget createField(
    FieldSchema schema,
    FormState formState,
    FieldUiState uiState,
  ) {
    // Performance tracking (AC requirement: <50ms per field)
    final stopwatch = Stopwatch()..start();

    try {
      final builder = _builders[schema.type];
      if (builder == null) {
        return _buildFallbackWidget(schema, uiState);
      }

      // Don't render if not visible
      if (!uiState.visible) {
        return const SizedBox.shrink();
      }

      final widget = builder(schema, formState, uiState);

      stopwatch.stop();
      // Log performance warning if exceeds target
      if (stopwatch.elapsedMilliseconds > 50) {
        debugPrint(
          'WARNING: Widget creation for ${schema.type} took ${stopwatch.elapsedMilliseconds}ms (target: <50ms)',
        );
      }

      return widget;
    } catch (e) {
      debugPrint('Error creating widget for field ${schema.id}: $e');
      return _buildFallbackWidget(schema, uiState);
    }
  }

  /// Build text field (Story A.2: AC-A.2.3 color coding, AC-A.2.7 voice input)
  Widget _buildTextField(
    FieldSchema schema,
    FormState formState,
    FieldUiState uiState,
  ) {
    final colorCode = _getFieldColorCode(schema);
    final controller = TextEditingController(
      text: formState.getValue(schema.id)?.toString(),
    );

    // Add voice input button for green (manual entry) fields
    final suffixIcon = colorCode == FieldColorCode.green
        ? VoiceInputButton(
            onTextRecognized: (text) {
              controller.text = text;
              formState.setValue(schema.id, text);
            },
          )
        : null;

    return TextFormField(
      controller: controller,
      decoration: FieldColors.getFieldDecoration(
        label: schema.label,
        colorCode: colorCode,
        placeholder: schema.uiConfig?.placeholder,
        helpText: schema.uiConfig?.helpText,
        errorText: uiState.error,
        suffixIcon: suffixIcon,
      ),
      enabled: !uiState.disabled,
      validator: (value) => uiState.error,
      onChanged: (value) => formState.setValue(schema.id, value),
    );
  }

