/// Field Color Codes for NDT Inspection Forms
/// Implements AC-A.2.3: Color-coded field system
/// Story A.2: Mobile Schema Rendering Engine
///
/// Visual distinction for field types:
/// - Yellow: Auto-filled from equipment/site registers (editable)
/// - Green: Manual technician entry (with voice-to-text support)
/// - Blue: Dropdown selections (with "Other" option)
/// - Orange: Pre-filled template defaults (editable)
/// - Grey: Static compliance text (read-only)
enum FieldColorCode {
  yellow, // Auto-filled
  green,  // Manual entry
  blue,   // Dropdown
  orange, // Pre-filled defaults
  grey,   // Read-only static
}

/// Field Colors configuration
class FieldColors {
  // Yellow: Auto-filled fields
  static const Color yellowBorder = Color(0xFFEAB308); // yellow-500
  static const Color yellowBackground = Color(0xFFFEF9C3); // yellow-100
  static const Color yellowText = Color(0xFF713F12); // yellow-900

  // Green: Manual entry fields
  static const Color greenBorder = Color(0xFF22C55E); // green-500
  static const Color greenBackground = Color(0xFFDCFCE7); // green-100
  static const Color greenText = Color(0xFF14532D); // green-900

  // Blue: Dropdown fields
  static const Color blueBorder = Color(0xFF3B82F6); // blue-500
  static const Color blueBackground = Color(0xFFDBEAFE); // blue-100
  static const Color blueText = Color(0xFF1E3A8A); // blue-900

  // Orange: Pre-filled defaults
  static const Color orangeBorder = Color(0xFFF97316); // orange-500
  static const Color orangeBackground = Color(0xFFFFEDD5); // orange-100
  static const Color orangeText = Color(0xFF7C2D12); // orange-900

  // Grey: Read-only static
  static const Color greyBorder = Color(0xFF9CA3AF); // gray-400
  static const Color greyBackground = Color(0xFFF3F4F6); // gray-100
  static const Color greyText = Color(0xFF374151); // gray-700

  /// Get border color for field color code
  static Color getBorderColor(FieldColorCode code) {
    switch (code) {
      case FieldColorCode.yellow:
        return yellowBorder;
      case FieldColorCode.green:
        return greenBorder;
      case FieldColorCode.blue:
        return blueBorder;
      case FieldColorCode.orange:
        return orangeBorder;
      case FieldColorCode.grey:
        return greyBorder;
    }
  }

  /// Get background color for field color code
  static Color getBackgroundColor(FieldColorCode code) {
    switch (code) {
      case FieldColorCode.yellow:
        return yellowBackground;
      case FieldColorCode.green:
        return greenBackground;
      case FieldColorCode.blue:
        return blueBackground;
      case FieldColorCode.orange:
        return orangeBackground;
      case FieldColorCode.grey:
        return greyBackground;
    }
  }

  /// Get text color for field color code
  static Color getTextColor(FieldColorCode code) {
    switch (code) {
      case FieldColorCode.yellow:
        return yellowText;
      case FieldColorCode.green:
        return greenText;
      case FieldColorCode.blue:
        return blueText;
      case FieldColorCode.orange:
        return orangeText;
      case FieldColorCode.grey:
        return greyText;
    }
  }

  /// Get field decoration with color coding
  /// Implements AC-A.8.1 (validation error display), AC-A.8.4 (spacing), AC-A.8.5 (Material 3 typography)
  static InputDecoration getFieldDecoration({
    required String label,
    required FieldColorCode colorCode,
    String? placeholder,
    String? helpText,
    String? errorText,
    Widget? suffixIcon,
    BuildContext? context,
  }) {
    return InputDecoration(
      labelText: label,
      hintText: placeholder,
      helperText: helpText,
      errorText: errorText,
      suffixIcon: suffixIcon,
      filled: true,
      fillColor: getBackgroundColor(colorCode),
      // AC-A.8.5: Material 3 typography
      // Labels use labelLarge from Material 3
