          ? Theme.of(context).textTheme.labelLarge
          : null,
      // AC-A.8.5: Field values use bodyLarge from Material 3
      hintStyle: context != null
          ? Theme.of(context).textTheme.bodyLarge?.copyWith(
              color: Theme.of(context).colorScheme.onSurfaceVariant.withValues(alpha: 0.6),
            )
          : null,
      // AC-A.8.5: Helper text uses bodySmall from Material 3
      helperStyle: context != null
          ? Theme.of(context).textTheme.bodySmall
          : null,
      // AC-A.8.1: Error text in red using Material 3 bodySmall
      errorStyle: context != null
          ? Theme.of(context).textTheme.bodySmall?.copyWith(
              color: Theme.of(context).colorScheme.error,
            )
          : const TextStyle(color: Color(0xFFF44336)), // Fallback red
      errorMaxLines: 3,
      // AC-A.8.4: Field spacing - 16px vertical margin applied in parent widget
      contentPadding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
      border: OutlineInputBorder(
        borderSide: BorderSide(color: getBorderColor(colorCode), width: 2),
      ),
      enabledBorder: OutlineInputBorder(
        borderSide: BorderSide(color: getBorderColor(colorCode), width: 2),
      ),
      focusedBorder: OutlineInputBorder(
        borderSide: BorderSide(color: getBorderColor(colorCode), width: 3),
      ),
      errorBorder: OutlineInputBorder(
        borderSide: BorderSide(
          color: context != null
              ? Theme.of(context).colorScheme.error
              : const Color(0xFFF44336),
          width: 2,
        ),
      ),
      focusedErrorBorder: OutlineInputBorder(
        borderSide: BorderSide(
          color: context != null
              ? Theme.of(context).colorScheme.error
              : const Color(0xFFF44336),
          width: 3,
        ),
      ),
    );
  }

  /// Get container decoration with color coding (for non-input widgets)
  static BoxDecoration getContainerDecoration(FieldColorCode colorCode) {
    return BoxDecoration(
      color: getBackgroundColor(colorCode),
      border: Border.all(color: getBorderColor(colorCode), width: 2),
      borderRadius: BorderRadius.circular(8),
    );
  }
